insert into dm.reg_reports(rep_tp_id, rep_nm, msr_prd_id, msr_prd_st_dttm, msr_prd_end_dttm, msr_prd_tp, msr_prd_caption, mime)
(select rep_tp.rep_tp_id rep_tp_id, rep_tp.name rep_nm, msr_prd_id, msr_prd.eff_dttm msr_prd_st_dttm, msr_prd.end_dttm msr_prd_end_dttm, msr_prd_tp.nm msr_prd_tp, msr_prd.caption msr_prd_caption, 'pdf' from dm.msr_prd join dm.rep_tp on type='REG' join dm.msr_prd_tp on msr_prd.msr_prd_tp_id = msr_prd_tp.msr_prd_tp_id);
insert into dm.reg_reports(rep_tp_id, rep_nm, msr_prd_id, msr_prd_st_dttm, msr_prd_end_dttm, msr_prd_tp, msr_prd_caption, mime)
(select rep_tp.rep_tp_id rep_tp_id, rep_tp.name rep_nm, msr_prd_id, msr_prd.eff_dttm msr_prd_st_dttm, msr_prd.end_dttm msr_prd_end_dttm, msr_prd_tp.nm msr_prd_tp, msr_prd.caption msr_prd_caption, 'xlsx' from dm.msr_prd join dm.rep_tp on type='REG' join dm.msr_prd_tp on msr_prd.msr_prd_tp_id = msr_prd_tp.msr_prd_tp_id);
insert into dm.reg_reports(rep_tp_id, rep_nm, msr_prd_id, msr_prd_st_dttm, msr_prd_end_dttm, msr_prd_tp, msr_prd_caption, mime)
(select rep_tp.rep_tp_id rep_tp_id, rep_tp.name rep_nm, msr_prd_id, msr_prd.eff_dttm msr_prd_st_dttm, msr_prd.end_dttm msr_prd_end_dttm, msr_prd_tp.nm msr_prd_tp, msr_prd.caption msr_prd_caption, 'docx' from dm.msr_prd join dm.rep_tp on type='REG' join dm.msr_prd_tp on msr_prd.msr_prd_tp_id = msr_prd_tp.msr_prd_tp_id);
